import { BaseCallbackHandler } from '@langchain/core/callbacks/base';
import { VexClient, VexTrace, GuardrailResult } from '@vex_dev/sdk';
import { LLMResult } from '@langchain/core/outputs';
import { ChainValues } from '@langchain/core/utils/types';

export class VexFlowiseCallbackHandler extends BaseCallbackHandler {
  name = 'VexFlowiseCallbackHandler';
  private vex: VexClient;
  private trace: VexTrace | null = null;

  constructor(vexClient: VexClient) {
    super();
    this.vex = vexClient;
  }

  async handleChainStart(
    chain: { id: string[] },
    inputs: ChainValues,
    runId: string
  ): Promise<void> {
    this.trace = await this.vex.traces.create({
      runId,
      chainId: chain.id.join('.'),
      inputs,
      framework: 'flowise',
    });
  }

  async handleLLMEnd(output: LLMResult, runId: string): Promise<void> {
    const text = output.generations[0]?.[0]?.text ?? '';

    // Validate LLM output before it reaches downstream nodes
    const result: GuardrailResult = await this.vex.guardrails.validate({
      traceId: this.trace?.id,
      content: text,
      checks: ['hallucination', 'prompt_injection', 'schema_compliance'],
    });

    if (!result.passed) {
      await this.vex.traces.flag(this.trace?.id, {
        reason: result.failedChecks,
        severity: result.severity,
        runId,
      });
      throw new Error(
        `Vex guardrail blocked LLM output: ${result.failedChecks.join(', ')}`
      );
    }
  }

  async handleToolEnd(output: string, runId: string): Promise<void> {
    // Detect silent tool failures (empty/null outputs)
    if (!output || output.trim() === '' || output === 'null') {
      await this.vex.alerts.send({
        traceId: this.trace?.id,
        type: 'tool_silent_failure',
        message: 'Flowise tool node returned empty output — possible silent failure',
        runId,
        severity: 'high',
      });
    }
  }

  async handleChainError(error: Error, runId: string): Promise<void> {
    await this.vex.traces.error(this.trace?.id, {
      error: error.message,
      stack: error.stack,
      runId,
    });
  }
}

import express, { Request, Response, NextFunction } from 'express';
import { VexFlowiseCallbackHandler } from './VexFlowiseCallbackHandler';
import { VexClient } from '@vex_dev/sdk';

const app = express();
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

// Middleware to inject Vex callback into every Flowise prediction request
app.use('/api/v1/prediction/:chatflowId', async (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  const { chatflowId } = req.params;
  const vexHandler = new VexFlowiseCallbackHandler(vex);

  // Attach Vex handler to the request context for Flowise to pick up
  req.body.overrideConfig = {
    ...req.body.overrideConfig,
    callbacks: [
      ...(req.body.overrideConfig?.callbacks ?? []),
      vexHandler,
    ],
  };

  // Tag the trace with chatflow metadata
  await vex.context.set({
    chatflowId,
    userId: req.headers['x-user-id'] as string,
    sessionId: req.body.sessionId,
  });

  next();
});

// Proxy to Flowise internal prediction handler
app.use('/api/v1/prediction', require('flowise/dist/routes/chatflows'));

app.listen(3001, () => {
  console.log('Vex-protected Flowise proxy running on port 3001');
});

import { VexClient, RetrievalGuardrailResult } from '@vex_dev/sdk';
import { Document } from '@langchain/core/documents';

const vex = new VexClient({ apiKey: process.env.VEX_API_KEY });

/**
 * Wrap this function around any Flowise vector store retriever
 * to enforce minimum relevance thresholds before LLM injection.
 */
export async function validateRetrievedDocuments(
  query: string,
  documents: Array<Document & { score?: number }>,
  options: {
    minRelevanceScore?: number;
    maxDocuments?: number;
    chatflowId: string;
  } = { minRelevanceScore: 0.72, maxDocuments: 4, chatflowId: 'unknown' }
): Promise<Document[]> {
  const result: RetrievalGuardrailResult = await vex.retrieval.validate({
    query,
    documents: documents.map((doc) => ({
      content: doc.pageContent,
      metadata: doc.metadata,
      score: doc.score ?? null,
    })),
    thresholds: {
      minRelevanceScore: options.minRelevanceScore ?? 0.72,
      maxDocuments: options.maxDocuments ?? 4,
    },
    context: {
      chatflowId: options.chatflowId,
      framework: 'flowise',
    },
  });

  if (result.filteredDocuments.length === 0) {
    await vex.alerts.send({
      type: 'retrieval_no_relevant_docs',
      message: `All retrieved documents fell below relevance threshold of ${options.minRelevanceScore} for query: "${query}"`,
      severity: 'high',
      metadata: { chatflowId: options.chatflowId, query, documentCount: documents.length },
    });
    // Return empty array — the LLM will respond with 'I don't know' rather than hallucinate
    return [];
  }

  return result.filteredDocuments.map(
    (d) => new Document({ pageContent: d.content, metadata: d.metadata })
  );
}

